INSERT INTO public.neuron_templates (name, description, category, blocks_template, is_public, usage_count, default_tags) VALUES ('Arhitectura Narativă a Șocului și Revelației', 'Formulă de storytelling în 8 pași: Fractură Cognitivă, Curiozitate, Erou, Criză, Revelație, Justificare, Reîntoarcere, Apel', 'Codul Cușnir', '[{"type":"heading","content":"Arhitectura Narativă a Șocului și Revelației"},{"type":"text","content":"Crează impact puternic printr-o alternanță între surpriză, tensiune, conexiune umană și claritate rațională."},{"type":"subheading","content":"1. Fractură Cognitivă"},{"type":"idea","content":"Sparge tiparele mentale cu o afirmație neașteptată care creează un decalaj cognitiv."},{"type":"subheading","content":"2. Curiozitate Primitivă"},{"type":"idea","content":"Creează o stare de anticipare folosind un mister sau o problemă urgentă."},{"type":"subheading","content":"3. Eroul Omului Obișnuit"},{"type":"idea","content":"Prezintă un personaj relatable care a trecut prin aceleași provocări ca audiența."},{"type":"subheading","content":"4. Criza (Tensiunea Maximă)"},{"type":"idea","content":"Construiește tensiune emoțională cu un moment de deznădejde."},{"type":"subheading","content":"5. Momentul Aha! (Revelația)"},{"type":"idea","content":"Prezintă soluția surprinzătoare care schimbă perspectiva."},{"type":"subheading","content":"6. Justificare Logică"},{"type":"idea","content":"Oferă argumente raționale: fapte, studii, date care validează soluția."},{"type":"subheading","content":"7. Reîntoarcerea la Audiență"},{"type":"idea","content":"Fă-i pe ei eroii propriei povești. Folosește întrebări de reflecție."},{"type":"subheading","content":"8. Apel la Acțiune Magnetic"},{"type":"idea","content":"Propune o oportunitate unică, evitând clișeele."}]'::jsonb, true, 0, ARRAY['storytelling','narativ','copywriting']);